import React from "react";
import MenuItem from "./MenuItem";

function Menu({ menuItemsData }) {
  return (
    <div className="Menu">
      {menuItemsData.map((menuItemData) => (
        <MenuItem
          key={menuItemData.id}
          name={menuItemData.name}
          description={menuItemData.description}
          price={menuItemData.price}
        />
      ))}
    </div>
  );
}

export default Menu;
